1391	  ModuleManager& module_manager, DecoderLibrary& decoder_lib,
1392	  const DeviceContext& device_ctx, const VprDeviceAnnotation& device_annotation,
1393	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
1394	  const TileAnnotation& tile_annotation,
1395	  const e_config_protocol_type& sram_orgz_type,
1396	  const CircuitModelId& sram_model,
1397	  const QLMemoryBankConfigSetting* ql_memory_bank_config_setting,
1398	  const bool& duplicate_grid_pin, const bool& group_config_block,
1399	  const bool& verbose) {
1400	  /* Start time count */
1401	  vtr::ScopedStartFinishTimer timer("Build grid modules");
1402	
1403	  int status = CMD_EXEC_SUCCESS;
1404	
1405	  /* Enumerate the types of logical tiles, and build a module for each
1406	   * Build modules for all the pb_types/pb_graph_nodes
1407	   * use a Depth-First Search Algorithm to print the sub-modules
1408	   * Note: DFS is the right way. Do NOT use BFS.
1409	   * DFS can guarantee that all the sub-modules can be registered properly
1410	   * to its parent in module manager
1411	   */
1412	  /* Build modules starting from the top-level pb_type/pb_graph_node, and
1413	   * traverse the graph in a recursive way */
1414	  VTR_LOG("Building logical tiles...");
1415	  VTR_LOGV(verbose, "\n");
1416	  for (const t_logical_block_type& logical_tile :
1417	       device_ctx.logical_block_types) {
1418	    /* Bypass empty pb_graph */
1419	    if (nullptr == logical_tile.pb_graph_head) {
1420	      continue;
1421	    }
1422	    rec_build_logical_tile_modules(
1423	      module_manager, decoder_lib, device_annotation, circuit_lib, mux_lib,
1424	      sram_orgz_type, sram_model, logical_tile.pb_graph_head,
1425	      group_config_block, verbose);
1426	  }
1427	  VTR_LOG("Done\n");
1428	
1429	  /* Enumerate the types of physical tiles
1430	   * Use the logical tile module to build the physical tiles
1431	   */
1432	  VTR_LOG("Building physical tiles...");
1433	  VTR_LOGV(verbose, "\n");
1434	  for (const t_physical_tile_type& physical_tile :
1435	       device_ctx.physical_tile_types) {
1436	    /* Bypass empty type or nullptr */
1437	    if (true == is_empty_type(&physical_tile)) {
1438	      continue;
1439	    } else if (physical_tile.is_io()) {
1440	      /* Special for I/O block:
1441	       * We will search the grids and see where the I/O blocks are located:
1442	       * - If a I/O block locates on border sides of FPGA fabric:
1443	       *   i.e., one or more from {TOP, RIGHT, BOTTOM, LEFT},
1444	       *   we will generate one module for each border side
1445	       * - If a I/O block locates in the center of FPGA fabric:
1446	       *   we will generate one module with NUM_2D_SIDES (same treatment as
1447	       * regular grids)
1448	       */
1449	      std::set<e_side> io_type_sides =
1450	        find_physical_io_tile_located_sides(device_ctx.grid, &physical_tile);
1451	      for (const e_side& io_type_side : io_type_sides) {
1452	        status = build_physical_tile_module(
1453	          module_manager, decoder_lib, device_annotation, circuit_lib,
1454	          sram_orgz_type, sram_model, &physical_tile, tile_annotation,
1455	          io_type_side, ql_memory_bank_config_setting, duplicate_grid_pin,
1456	          group_config_block, device_ctx.arch->perimeter_cb, verbose);
1457	        if (status != CMD_EXEC_SUCCESS) {
1458	          return CMD_EXEC_FATAL_ERROR;
1459	        }
1460	      }
1461	    } else {
1462	      /* For CLB and heterogenenous blocks */
1463	      status = build_physical_tile_module(
1464	        module_manager, decoder_lib, device_annotation, circuit_lib,
1465	        sram_orgz_type, sram_model, &physical_tile, tile_annotation,
1466	        NUM_2D_SIDES, ql_memory_bank_config_setting, duplicate_grid_pin,
1467	        group_config_block, device_ctx.arch->perimeter_cb, verbose);
1468	      if (status != CMD_EXEC_SUCCESS) {
1469	        return CMD_EXEC_FATAL_ERROR;
1470	      }
1471	    }
1472	  }
1473	  VTR_LOG("Done\n");
1474	
1475	  return status;
1476	}
