1302	void build_flatten_routing_modules(
1303	  ModuleManager& module_manager, DecoderLibrary& decoder_lib,
1304	  const DeviceContext& device_ctx, const VprDeviceAnnotation& device_annotation,
1305	  const RRGraphInEdges& in_edges, const DeviceRRGSB& device_rr_gsb,
1306	  const CircuitLibrary& circuit_lib,
1307	  const e_config_protocol_type& sram_orgz_type,
1308	  const CircuitModelId& sram_model, const bool& group_config_block,
1309	  const bool& verbose) {
1310	  vtr::ScopedStartFinishTimer timer("Build routing modules...");
1311	
1312	  vtr::Point<size_t> sb_range = device_rr_gsb.get_gsb_range();
1313	
1314	  /* Build unique switch block modules */
1315	  for (size_t ix = 0; ix < sb_range.x(); ++ix) {
1316	    for (size_t iy = 0; iy < sb_range.y(); ++iy) {
1317	      const RRGSB& rr_gsb = device_rr_gsb.get_gsb(ix, iy);
1318	      if (false == device_rr_gsb.get_gsb_edges(ix, iy).is_sb_exist(rr_gsb)) {
1319	        continue;
1320	      }
1321	      build_switch_block_module(
1322	        module_manager, decoder_lib, device_annotation, device_ctx.grid,
1323	        device_ctx.rr_graph, in_edges, circuit_lib, sram_orgz_type, sram_model,
1324	        device_rr_gsb, rr_gsb, group_config_block, verbose);
1325	    }
1326	  }
1327	  if (false == module_manager.group_routing()) {
1328	    build_flatten_connection_block_modules(
1329	      module_manager, decoder_lib, device_ctx, in_edges, device_annotation,
1330	      device_rr_gsb, circuit_lib, sram_orgz_type, sram_model, e_rr_type::CHANX,
1331	      group_config_block, verbose);
1332	
1333	    build_flatten_connection_block_modules(
1334	      module_manager, decoder_lib, device_ctx, in_edges, device_annotation,
1335	      device_rr_gsb, circuit_lib, sram_orgz_type, sram_model, e_rr_type::CHANY,
1336	      group_config_block, verbose);
1337	  }
1338	}
