976	static void rec_build_logical_tile_modules(
977	  ModuleManager& module_manager, DecoderLibrary& decoder_lib,
978	  const VprDeviceAnnotation& device_annotation,
979	  const CircuitLibrary& circuit_lib, const MuxLibrary& mux_lib,
980	  const e_config_protocol_type& sram_orgz_type,
981	  const CircuitModelId& sram_model, t_pb_graph_node* physical_pb_graph_node,
982	  const bool& group_config_block, const bool& verbose) {
983	  /* Check cur_pb_graph_node*/
984	  VTR_ASSERT(nullptr != physical_pb_graph_node);
985	
986	  /* Get the pb_type definition related to the node */
987	  t_pb_type* physical_pb_type = physical_pb_graph_node->pb_type;
988	
989	  /* Find the mode that physical implementation of a pb_type */
990	  t_mode* physical_mode = device_annotation.physical_mode(physical_pb_type);
991	
992	  /* For non-leaf node in the pb_type graph:
993	   * Recursively Depth-First Generate all the child pb_type at the level
994	   */
995	  if (false == is_primitive_pb_type(physical_pb_type)) {
996	    for (int ipb = 0; ipb < physical_mode->num_pb_type_children; ++ipb) {
997	      /* Go recursive to visit the children */
998	      rec_build_logical_tile_modules(
999	        module_manager, decoder_lib, device_annotation, circuit_lib, mux_lib,
1000	        sram_orgz_type, sram_model,
1001	        &(physical_pb_graph_node
1002	            ->child_pb_graph_nodes[physical_mode->index][ipb][0]),
1003	        group_config_block, verbose);
1004	    }
1005	  }
1006	
1007	  /* For leaf node, a primitive Verilog module will be generated */
1008	  if (true == is_primitive_pb_type(physical_pb_type)) {
1009	    build_primitive_block_module(module_manager, decoder_lib, device_annotation,
1010	                                 circuit_lib, sram_orgz_type, sram_model,
1011	                                 physical_pb_graph_node, group_config_block,
1012	                                 verbose);
1013	    /* Finish for primitive node, return */
1014	    return;
1015	  }
1016	
1017	  /* Generate the name of the Verilog module for this pb_type */
1018	  std::string pb_module_name =
1019	    generate_physical_block_module_name(physical_pb_type);
1020	
1021	  VTR_LOGV(verbose, "Building module '%s'...\n", pb_module_name.c_str());
1022	
1023	  /* Register the Verilog module in module manager */
1024	  ModuleId pb_module = module_manager.add_module(pb_module_name);
1025	  VTR_ASSERT(true == module_manager.valid_module_id(pb_module));
1026	
1027	  /* Label module usage */
1028	  module_manager.set_module_usage(pb_module, ModuleManager::MODULE_GRID);
1029	
1030	  /* Add ports to the Verilog module */
1031	  add_pb_type_ports_to_module_manager(module_manager, pb_module,
1032	                                      physical_pb_type);
1033	
1034	  /* Vectors to record all the memory modules have been added
1035	   * They are used to add module nets of configuration bus
1036	   */
1037	  std::vector<ModuleId> memory_modules;
1038	  std::vector<size_t> memory_instances;
1039	
1040	  e_config_protocol_type mem_module_type =
1041	    group_config_block ? CONFIG_MEM_FEEDTHROUGH : sram_orgz_type;
1042	
1043	  /* Add all the child Verilog modules as instances */
1044	  for (int ichild = 0; ichild < physical_mode->num_pb_type_children; ++ichild) {
1045	    /* Get the name and module id for this child pb_type */
1046	    std::string child_pb_module_name = generate_physical_block_module_name(
1047	      &(physical_mode->pb_type_children[ichild]));
1048	    ModuleId child_pb_module = module_manager.find_module(child_pb_module_name);
1049	    /* We must have one valid id! */
1050	    VTR_ASSERT(true == module_manager.valid_module_id(child_pb_module));
1051	
1052	    /* Each child may exist multiple times in the hierarchy*/
1053	    for (int inst = 0; inst < physical_mode->pb_type_children[ichild].num_pb;
1054	         ++inst) {
1055	      size_t child_instance_id =
1056	        module_manager.num_instance(pb_module, child_pb_module);
1057	      /* Ensure the instance of this child module is the same as placement
1058	       * index, This check is necessary because placement_index is used to
1059	       * identify instance id for children when adding local interconnection for
1060	       * this pb_type
1061	       */
1062	      VTR_ASSERT(child_instance_id ==
1063	                 (size_t)physical_pb_graph_node
1064	                   ->child_pb_graph_nodes[physical_mode->index][ichild][inst]
1065	                   .placement_index);

